// 3
// 4

// Massiv üzərində for dövrü
const fruits = ['alma', 'armud', 'nar'];
for (let i = 0; i < fruits.length; i++) {
  console.log(fruits[i]);
}
// Çıxış:
// alma
// armud
// nar

// break və continue nümunəsi
for (let i = 0; i < 5; i++) {
  if (i === 3) {
    break; // dövrü dayandırır
  }
  console.log(i);
}
// Çıxış:
// 0
// 1
// 2

for (let i = 0; i < 5; i++) {
  if (i === 3) {
    continue; // 3-ü atlayır
  }
  console.log(i);
}
// Çıxış:
// 0
// 1
// 2
// 4

