content.text:
The syntax of a `for` loop is:
```javascript
for (initialization; condition; update) {
  // code to execute
}
```
- **Initialization**: Sets a variable before the loop starts (e.g., `let i = 0;`).
- **Condition**: Checked before each iteration (e.g., `i < 5;`).
- **Update**: Updates the variable after each iteration (e.g., `i++`).

content.code:
// Basic for loop example
for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Output:
// 0
// 1
// 2
// 3
// 4

// for loop with an array
const fruits = ['apple', 'pear', 'orange'];
for (let i = 0; i < fruits.length; i++) {
  console.log(fruits[i]);
}
// Output:
// apple
// pear
// orange

// break and continue example
for (let i = 0; i < 5; i++) {
  if (i === 3) {
    break; // stops the loop
  }
  console.log(i);
}
// Output:
// 0
// 1
// 2

for (let i = 0; i < 5; i++) {
  if (i === 3) {
    continue; // skips 3
  }
  console.log(i);
}
// Output:
// 0
// 1
// 2
// 4

// Error-prone example
// Error: Infinite loop
// for (let i = 0; i < 5; i--) { // i-- creates an infinite loop
//   console.log(i);
// }
// Correct approach
for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Output:
// 0
// 1
// 2
// 3
// 4

