// 3
// 4

// Цикл for с массивом
const fruits = ['яблоко', 'груша', 'апельсин'];
for (let i = 0; i < fruits.length; i++) {
  console.log(fruits[i]);
}
// Вывод:
// яблоко
// груша
// апельсин

// Пример break и continue
for (let i = 0; i < 5; i++) {
  if (i === 3) {
    break; // останавливает цикл
  }
  console.log(i);
}
// Вывод:
// 0
// 1
// 2

for (let i = 0; i < 5; i++) {
  if (i === 3) {
    continue; // пропускает 3
  }
  console.log(i);
}
// Вывод:
// 0
// 1
// 2
// 4

